#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+5;
#define int long long
#define pii pair<int,int>
vector<pii> v[maxn];
vector<int> dj(int tot,int s) {
	priority_queue<pii,vector<pii>,greater<pii>>pq;
	vector<int> dis(tot+5,LLONG_MAX);
	pq.push({0,s});
	while(pq.size()) {
		auto p=pq.top();
		pq.pop();
		if(p.first>dis[p.second]) {
			continue;
		}
		for(auto x:v[p.second]) {
			if(x.second+p.first<dis[x.first]) {
				dis[x.first]=p.first+x.second;
				pq.push({dis[x.first],x.first});
			}
		}
	}
	return dis;
}
int n,m,k;
signed main() {
	cin>>n>>m>>k;
	for(int i=0,x,y,z; i<m; i++) {
		cin>>x>>y>>z;
		for(int j=0; j<=k; j++) {
			v[x+j*n].emplace_back(y+j*n,z);
			v[y+j*n].emplace_back(x+j*n,z);
			if(j<k) {
				v[x+j*n].emplace_back(y+(j+1)*n,z/2);
				v[y+j*n].emplace_back(x+(j+1)*n,z/2);
			}
		}
	}
	int tot=n*(k+1);
	vector<int> dis=dj(tot,1);
	int ans=LLONG_MAX;
	for(int i=0; i<=k; i++) {
		ans=min(ans,dis[n+i*n]);
	}
	cout<<ans;
	return 0;
}
